/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007;

    // The number of people to the left of pos: pos (indices 0 to pos-1)
    const leftCount = pos;
    // The number of people to the right of pos: n - 1 - pos (indices pos+1 to n-1)
    const rightCount = n - 1 - pos;

    // Let L_seen be the number of people to the left (i < pos) seen by pos.
    // A person i < pos is seen iff they choose 'L'.
    // The number of choices for the left side is 2^leftCount.
    // We need exactly L_seen people to choose 'L' among leftCount people.
    // The number of ways to choose exactly L_seen 'L's from leftCount people is C(leftCount, L_seen).

    // Let R_seen be the number of people to the right of pos (i > pos) seen by pos.
    // A person i > pos is seen iff they choose 'R'.
    // We need exactly R_seen people to choose 'R' among rightCount people.
    // The number of ways to choose exactly R_seen 'R's from rightCount people is C(rightCount, R_seen).

    // Total seen: L_seen + R_seen = k.
    // We iterate over all possible values for L_seen (from 0 to leftCount).
    // Then R_seen must be k - L_seen. We check if 0 <= R_seen <= rightCount.

    // Precompute factorials and inverse factorials for combinations C(n, k) mod MOD
    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    const invFact = new Array(MAX_N + 1);

    fact[0] = 1;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    // Function for modular exponentiation (a^b mod m)
    const power = (base, exp) => {
        let res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 === 1) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp = Math.floor(exp / 2);
        }
        return res;
    };

    // Function for modular inverse (a^(-1) mod m) using Fermat's Little Theorem
    const modInverse = (n) => {
        return power(n, MOD - 2);
    };

    invFact[MAX_N] = modInverse(fact[MAX_N]);
    for (let i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }

    // Combination function C(n, k) mod MOD
    const combinations = (n_val, k_val) => {
        if (k_val < 0 || k_val > n_val) {
            return 0;
        }
        // C(n, k) = n! / (k! * (n-k)!)
        let res = fact[n_val];
        res = (res * invFact[k_val]) % MOD;
        res = (res * invFact[n_val - k_val]) % MOD;
        return res;
    };

    // 1. Calculate the contribution from people other than pos
    let countOthers = 0;
    for (let l_seen = 0; l_seen <= leftCount; l_seen++) {
        const r_seen = k - l_seen;

        if (r_seen >= 0 && r_seen <= rightCount) {
            // Ways to achieve l_seen on the left: C(leftCount, l_seen)
            const waysLeft = combinations(leftCount, l_seen);

            // Ways to achieve r_seen on the right: C(rightCount, r_seen)
            const waysRight = combinations(rightCount, r_seen);

            // Total ways for this (l_seen, r_seen) pair: product
            let currentWays = (waysLeft * waysRight) % MOD;

            countOthers = (countOthers + currentWays) % MOD;
        }
    }

    // 2. Account for the choice of direction for person at pos
    // The choice of person at pos ('L' or 'R') does not affect the count k,
    // as the visibility rules are defined only based on the observer (pos) and the choices of others.
    // The person at pos can choose 'L' or 'R' (2 options).
    const waysPos = 2;

    // Total possibilities = countOthers * waysPos
    let totalWays = (countOthers * waysPos) % MOD;

    return totalWays;
}

